+// --- String-to-enum parsers ---
+
+fn parse_action_kind(s: &str) -> Option<ActionKind> {
+    let quoted = format!("\"{s}\"");
+    serde_json::from_str(&quoted).ok()
+}
+
+fn parse_actor_kind(s: &str) -> Option<ActorKind> {
+    let quoted = format!("\"{s}\"");
+    serde_json::from_str(&quoted).ok()
+}
+
+fn parse_policy_surface(s: &str) -> Option<PolicySurface> {
+    let quoted = format!("\"{s}\"");
+    serde_json::from_str(&quoted).ok()
+}
